export const AOL_100 = [
  // ==================== EASY (30) ====================
  {id:"aol-201",d:"easy",t:"TMAE Concepts",q:"Which of the following lists the TMAE concepts in order from MOST BASIC to MOST INTERPRETIVE?",c:["A. Assessment → Test → Measurement → Evaluation","B. Test → Measurement → Assessment → Evaluation","C. Evaluation → Assessment → Measurement → Test","D. Measurement → Test → Evaluation → Assessment"],a:"B",e:"CORRECT ORDER: Test (instrument) → Measurement (assigning numbers) → Assessment (collecting/interpreting data) → Evaluation (making judgments). Each step builds on the previous."},
  {id:"aol-202",d:"easy",t:"Purposes of Assessment",q:"Which type of assessment is associated with the use of SCORING RUBRICS and REFLECTION PAPERS?",c:["A. Assessment FOR Learning — Placement","B. Assessment OF Learning — Summative","C. Assessment AS Learning — self-assessment tools","D. Assessment FOR Learning — Diagnostic"],a:"C",e:"Assessment AS Learning uses SCORING RUBRICS (students self-assess using rubrics) and REFLECTION PAPERS/JOURNALS (students reflect on their own learning). These are tools for self-directed learning."},
  {id:"aol-203",d:"easy",t:"Diagnostic Assessment",q:"The NCAE (National Career Assessment Examination) and entrance examinations are examples of which type of assessment?",c:["A. Summative Assessment — given after instruction","B. Formative Assessment — given during instruction","C. Diagnostic Assessment — given before instruction to diagnose prior knowledge","D. Self-Assessment — student-driven reflection"],a:"C",e:"DIAGNOSTIC Assessment is done BEFORE instruction. NCAE and entrance exams are classic diagnostic tools — they determine what students already know (prior knowledge, skills, and misconceptions) before formal instruction begins."},
  {id:"aol-204",d:"easy",t:"Portfolio Types",q:"Which portfolio type is MOST APPROPRIATE for a student applying for a college scholarship?",c:["A. Assessment Portfolio — shows learning based on objectives","B. Working/Development Portfolio — shows growth over time","C. Display/Best Work Portfolio — showcases most outstanding work and achievements","D. Diagnostic Portfolio — shows areas of difficulty"],a:"C",e:"DISPLAY/BEST WORK PORTFOLIO — very useful for college applications because it presents the student's MOST OUTSTANDING WORK, best efforts, and best performance — what the student wants to present to admissions committees."},
  {id:"aol-205",d:"easy",t:"Scoring Rubric Parts",q:"The two required parts of a scoring rubric are criteria and:",c:["A. Grades and percentages","B. Learning objectives and competencies","C. Descriptions of levels of performance for those criteria","D. Student reflections and teacher comments"],a:"C",e:"The TWO PARTS of a scoring rubric: (1) Coherent sets of CRITERIA, and (2) DESCRIPTIONS OF THE LEVELS OF PERFORMANCE for those criteria. These two parts together make up a complete, functional rubric."},
  {id:"aol-206",d:"easy",t:"Types of Rubrics",q:"Which type of rubric does NOT permit differential weighting of the qualities of a product or performance?",c:["A. Analytic Rubric","B. Holistic Rubric","C. Criterion-referenced Rubric","D. Checklist-based Rubric"],a:"B",e:"HOLISTIC RUBRIC does NOT permit DIFFERENTIAL WEIGHTING of qualities — there is only ONE rating for the entire performance. Analytic Rubric DOES permit differential weighting (different criteria can have different weights)."},
  {id:"aol-207",d:"easy",t:"Item Difficulty",q:"An item with Difficulty Index = 0.50 is classified as:",c:["A. Difficult — Revise or Discard","B. Right Difficulty — Retain","C. Easy — Revise or Discard","D. Perfect — no need to review"],a:"B",e:"DI = 0.50 is within the range 0.26-0.75 = RIGHT DIFFICULTY = RETAIN. 0.50 is actually ideal — 50% of students got it right, 50% wrong = maximum discrimination potential."},
  {id:"aol-208",d:"easy",t:"Measures of Central Tendency",q:"Which measure of central tendency can be used for BOTH QUANTITATIVE AND QUALITATIVE data?",c:["A. Mean","B. Median","C. Mode","D. Standard Deviation"],a:"C",e:"The MODE can be used for QUANTITATIVE (numerical) AND QUALITATIVE (categorical) data. Example: Mode of shirt colors = 'Blue' (qualitative). Mean and Median require numerical data."},
  {id:"aol-209",d:"easy",t:"Standard Deviation",q:"A SMALL Standard Deviation indicates that scores are:",c:["A. Widely dispersed and heterogeneous","B. Closely clustered and homogeneous","C. Skewed to the right","D. Bimodal with two peaks"],a:"B",e:"SMALL SD = scores are CLOSELY CLUSTERED near the mean, HOMOGENEOUS (similar performance). LARGE SD = widely dispersed, HETEROGENEOUS (varied performance)."},
  {id:"aol-210",d:"easy",t:"Skewness",q:"In a POSITIVELY SKEWED distribution, which statement about Mean, Median, and Mode is CORRECT?",c:["A. Mode > Median > Mean","B. Mean = Median = Mode","C. Mean > Median > Mode","D. Median > Mean > Mode"],a:"C",e:"POSITIVELY SKEWED: Mean > Median > Mode. The mean is pulled to the RIGHT by extreme high scores (thin tail to the right). Remember: PRDL = Positive=Right=Difficult=Low (most scores low)."},
  {id:"aol-211",d:"easy",t:"Normal Distribution Properties",q:"Which of the following is a property of the NORMAL DISTRIBUTION?",c:["A. It has two peaks (bimodal)","B. It is skewed to the right or left","C. It is bell-shaped and symmetrical to the mean","D. The mean is always greater than the median"],a:"C",e:"NORMAL DISTRIBUTION is: (1) Unimodal (single peak), (2) BELL-SHAPED and SYMMETRICAL to the mean, (3) Mean=Median=Mode, (4) End tails extend indefinitely. Not bimodal, not skewed."},
  {id:"aol-212",d:"easy",t:"Validity Types",q:"Which type of validity is established by examining the PHYSICAL APPEARANCE of the assessment instrument?",c:["A. Content Validity","B. Face Validity","C. Criterion-related Validity","D. Predictive Validity"],a:"B",e:"FACE VALIDITY is established by examining the PHYSICAL APPEARANCE of the instrument (e.g., colors, layout, format). It is the most superficial type — based on looks rather than statistical evidence."},
  {id:"aol-213",d:"easy",t:"Reliability",q:"Which method of establishing reliability requires the test to be given ONLY ONCE and then divides the test into two equal halves?",c:["A. Test-Retest Method","B. Equivalent Forms Method","C. Test-Retest with Equivalent Forms","D. Split-Half Method"],a:"D",e:"SPLIT-HALF METHOD — test is given ONCE. Score is equivalent halves (e.g., odd and even items). The two halves' scores are correlated. Only ONE administration required."},
  {id:"aol-214",d:"easy",t:"Kurtosis Types",q:"A MESOKURTIC curve is described as:",c:["A. A very tall, narrow, peaked curve","B. A flat, wide curve with scores spread out","C. A normal bell-shaped curve — scores are just right, not too high or too low","D. A curve skewed to the left"],a:"C",e:"MESOKURTIC = NORMAL bell curve. Scores are JUST RIGHT — not too peaked (leptokurtic) and not too flat (platykurtic). Most scores are average, not too high or too low."},
  {id:"aol-215",d:"easy",t:"Percentile Rank",q:"A student at the 90th percentile has SURPASSED what percentage of the norm group?",c:["A. 10%","B. 50%","C. 90%","D. 100%"],a:"C",e:"90th percentile = student scored HIGHER than 90% of the norm group. The student SURPASSED 90% of classmates and belongs to the TOP 10% of the group."},
  {id:"aol-216",d:"easy",t:"K-12 Curriculum",q:"Under the K-12 Curriculum (RA 10533), Grades 11 and 12 are known as:",c:["A. Junior High School","B. Senior High School","C. Technical-Vocational School","D. Basic Education School"],a:"B",e:"Under K-12, GRADES 11 and 12 = SENIOR HIGH SCHOOL (SHS). Grades 7-10 = Junior High School. Grades 1-6 = Elementary. Plus Mandatory Kindergarten."},
  {id:"aol-217",d:"easy",t:"Completion Type",q:"In a completion type item, the blank should be placed at the:",c:["A. Beginning of the sentence","B. Middle of the sentence","C. End or near the end of the sentence","D. Anywhere in the sentence for variety"],a:"C",e:"RULE #3 for Completion Type: The blank should be at the END or NEAR THE END of the sentence. This allows students to read the full context first before encountering the blank they need to fill."},
  {id:"aol-218",d:"easy",t:"Matching Type",q:"In a Matching Type test, the STEMS (Column A) should be:",c:["A. Shorter in construction than the options","B. Longer in construction than the options","C. Equal in length to all options in Column B","D. Listed alphabetically in Column A"],a:"B",e:"RULE #2 for Matching Type: The STEM (longer in construction than the options) must be in the FIRST COLUMN (Column A) while the OPTIONS (usually SHORTER) must be in the SECOND COLUMN (Column B)."},
  {id:"aol-219",d:"easy",t:"Essay Tests",q:"According to Essay Rule #1, a teacher writing essay items should:",c:["A. Always use extended essay format for more comprehensive assessment","B. Specify HOW students should respond (recall, organize, and present knowledge in a logical, integrated answer)","C. Avoid restricting the scope of the essay to allow student creativity","D. Give essay tests only for summative purposes"],a:"B",e:"Essay RULE #1 — SPECIFY HOW students should respond. Tell students what they should do: recall factual knowledge, organize it, and present it as a logical, integrated answer to the question."},
  {id:"aol-220",d:"easy",t:"Assessment Terminology",q:"The FOUR classes of evidence that can be placed in a student portfolio are Artifacts, Reproductions, Attestations, and:",c:["A. Credentials","B. Productions","C. Certifications","D. Evaluations"],a:"B",e:"The FOUR classes of portfolio evidence are: (1) ARTIFACTS (inside classroom work), (2) REPRODUCTIONS (outside classroom work), (3) ATTESTATIONS (by teacher or responsible persons), (4) PRODUCTIONS (by the student themselves)."},
  {id:"aol-221",d:"easy",t:"Multiple Choice Guidelines",q:"Which Multiple Choice rule states that 'distractors should be EQUALLY PLAUSIBLE and ATTRACTIVE'?",c:["A. Rule #1 — Avoid unfamiliar words","B. Rule #3 — Avoid complex word arrangements","C. Rule #4 — Distractors should be equally plausible and attractive; make all alternatives work","D. Rule #6 — Avoid stems that reveal answers to other items"],a:"C",e:"RULE #4 — Distractors should be EQUALLY PLAUSIBLE AND ATTRACTIVE — make all alternatives work. If distractors are obviously wrong, students can guess correctly without knowledge."},
  {id:"aol-222",d:"easy",t:"Discrimination Index Range",q:"A Discrimination Index of -0.55 to 0.45 indicates the item is:",c:["A. Discriminating — Include","B. Questionable — Discard","C. Non-discriminating — Revise","D. Perfect — Retain as is"],a:"C",e:"Discrimination Index -0.55 to 0.45 = NON-DISCRIMINATING = REVISE. Range 0.46 to 1.0 = Discriminating = Include. Range -1.0 to -0.56 = Can discriminate but questionable = Discard."},
  {id:"aol-223",d:"easy",t:"Measures of Variability",q:"Which measure of variability is MOST EASILY AFFECTED by extreme scores?",c:["A. Standard Deviation","B. Quartile Deviation","C. Range","D. Variance"],a:"C",e:"RANGE (HS-LS) is MOST EASILY AFFECTED by extreme scores — changing just ONE extreme score dramatically changes the range. QD considers only the middle 50% so it reduces extreme score influence."},
  {id:"aol-224",d:"easy",t:"Z-Score",q:"A Z-score of ZERO (Z=0) means the score is:",c:["A. Below the mean","B. Above the mean","C. Exactly at the mean","D. At the 100th percentile"],a:"C",e:"Z = 0 means the score is EXACTLY AT THE MEAN — zero standard deviations from the mean. A positive Z is above the mean; a negative Z is below the mean."},
  {id:"aol-225",d:"easy",t:"T-Score",q:"A T-score of 50 corresponds to which Z-score?",c:["A. Z = -1","B. Z = 0","C. Z = +1","D. Z = +2"],a:"B",e:"T = 10z + 50. When T=50: 50 = 10z + 50 → 10z = 0 → z = 0. T=50 corresponds to Z=0 (exactly at the mean). T=50 IS the mean in T-score units."},
  {id:"aol-226",d:"easy",t:"Positive Correlation",q:"As the temperature INCREASES, ice cream sales also INCREASE. This illustrates:",c:["A. Negative Correlation — indirect relation","B. No Correlation — no relationship","C. Positive Correlation — direct relation; both variables move in the same direction","D. Zero Correlation"],a:"C",e:"POSITIVE CORRELATION (Direct Relation) — as one variable INCREASES (temperature), the other also INCREASES (ice cream sales). Both variables move in the same direction."},
  {id:"aol-227",d:"easy",t:"Negative Correlation",q:"As the number of cigarettes smoked per day INCREASES, life expectancy DECREASES. This is an example of:",c:["A. Positive Correlation","B. No Correlation","C. Negative Correlation — indirect/inverse relation","D. Zero Correlation"],a:"C",e:"NEGATIVE CORRELATION (Indirect/Inverse Relation) — as one variable INCREASES (cigarettes), the other DECREASES (life expectancy). Opposite directions = negative/inverse relationship."},
  {id:"aol-228",d:"easy",t:"Holistic Rubric Advantages",q:"The PRIMARY ADVANTAGE of a Holistic Rubric over an Analytic Rubric is:",c:["A. It clearly describes the degree to which each criterion is satisfied","B. It permits differential weighting of qualities","C. It allows fast assessment with one overall rating","D. It helps pinpoint specific areas of strength and weakness"],a:"C",e:"HOLISTIC RUBRIC advantage: It ALLOWS FAST ASSESSMENT. One overall rating for the entire performance is much quicker than rating each dimension separately (as in analytic). Best when quick scoring is the priority."},
  {id:"aol-229",d:"easy",t:"Analytic Rubric Advantages",q:"The PRIMARY ADVANTAGE of an Analytic Rubric over a Holistic Rubric is that it:",c:["A. Provides only one score for the entire performance","B. Is faster to use","C. Clearly describes the degree to which each criterion is satisfied AND helps pinpoint specific strengths and weaknesses","D. Is simpler to construct"],a:"C",e:"ANALYTIC RUBRIC advantage: Clearly DESCRIBES the degree to which each criterion is satisfied and helps pinpoint specific areas of STRENGTH and WEAKNESS. Better for detailed, formative feedback."},
  {id:"aol-230",d:"easy",t:"K-12 Curriculum Structure",q:"The 2002 BEC had how many total years of basic education (excluding college)?",c:["A. 10 years (Grades 1-10)","B. 10 years (Elementary + High School without Kindergarten)","C. 12 years (with Kindergarten)","D. 13 years (with Senior High School)"],a:"B",e:"2002 BEC = 6 years elementary + 4 years high school = 10 YEARS (without compulsory Kindergarten). K-12 = Mandatory Kinder + 6 years elementary + 4 years JHS + 2 years SHS = 13 years total."},

  // ==================== MODERATE (50) ====================
  {id:"aol-231",d:"moderate",t:"Assessment Design",q:"A teacher is deciding between using a Holistic or Analytic Rubric to score students' research papers. She needs to provide detailed, specific feedback to help students improve before the next draft. Which should she use and why?",c:["A. Holistic — faster and gives a clear overall picture","B. Analytic — clearly describes the degree to which each criterion is satisfied and helps pinpoint specific strengths and weaknesses for targeted improvement","C. Both are equally appropriate for this purpose","D. Neither — essay scoring should use only letter grades"],a:"B",e:"ANALYTIC RUBRIC is better for FORMATIVE FEEDBACK — it clearly describes each dimension's level and helps students pinpoint exactly WHERE to improve. Holistic gives only one score; analytic gives criterion-by-criterion guidance."},
  {id:"aol-232",d:"moderate",t:"Item Analysis Integration",q:"A teacher's item analysis reveals: Item 1 (DI=0.50, D=0.60), Item 2 (DI=0.20, D=0.25), Item 3 (DI=0.80, D=0.10), Item 4 (DI=0.40, D=-0.40). What is the CORRECT ACTION for each item?",c:["A. Retain 1, Retain 2, Revise 3, Retain 4","B. Retain 1, Revise 2, Discard/Revise 3, Discard 4","C. All items should be retained","D. Revise all items — none meet both criteria"],a:"B",e:"Item 1: DI=0.50✓ + D=0.60✓ = RETAIN. Item 2: DI=0.20✗ + D=0.25✗ (0.25 is in -0.55 to 0.45 range = non-discriminating) = Both bad → REVISE/DISCARD. Item 3: DI=0.80✗ + D=0.10✗ = Both bad → REVISE/DISCARD. Item 4: DI=0.40✓ + D=-0.40✗ = One good, one very bad (-0.40 is in -0.55 to 0.45 range) → REVISE."},
  {id:"aol-233",d:"moderate",t:"Validity Application",q:"A teacher claims her new stress-assessment questionnaire is valid. A reviewer examines the questionnaire and notes it only contains physiological stress indicators (heart rate, sleep disruption) but misses psychological and behavioral stress indicators. Which type of validity is MOST COMPROMISED?",c:["A. Face Validity — the questionnaire doesn't look valid","B. Content Validity — the instrument doesn't comprehensively cover the full domain of 'stress'","C. Predictive Validity — can't predict future stress accurately","D. Reliability — scores will be inconsistent"],a:"B",e:"CONTENT VALIDITY — the instrument must cover the FULL DOMAIN of what it claims to measure. Missing psychological and behavioral indicators means the questionnaire doesn't represent the full construct of 'stress' = Content Validity compromised."},
  {id:"aol-234",d:"moderate",t:"Assessment Design Application",q:"A science teacher wants to assess students' ability to apply the scientific method in real-world situations. Which assessment approach is MOST APPROPRIATE?",c:["A. 50-item True-False test on scientific method definitions","B. A laboratory performance task where students design and conduct an actual experiment, scored with an analytic rubric","C. A 20-item multiple choice test on steps of the scientific method","D. A Matching Type test matching scientific method steps with their definitions"],a:"B",e:"AUTHENTIC ASSESSMENT — performance task in a laboratory setting APPROXIMATES THE REAL WORLD of scientific inquiry. Scored with an analytic rubric for reliability. Measures actual APPLICATION of scientific method, not just recall."},
  {id:"aol-235",d:"moderate",t:"Skewness Interpretation",q:"A teacher administers a final exam. She finds Mean=78, Median=80, Mode=83. Without looking at a graph, describe the distribution and what it tells about student performance.",c:["A. Positively Skewed — Mean < Median < Mode; test was easy, most scores HIGH","B. Positively Skewed — Mean < Median < Mode; test was difficult, most scores LOW","C. Negatively Skewed — Mean < Median < Mode; most scores HIGH, test was EASY","D. Normal Distribution — all three are approximately equal"],a:"C",e:"Mean (78) < Median (80) < Mode (83) = NEGATIVELY SKEWED (Mode > Median > Mean = left tail). Most scores are HIGH (above mean). Test was EASY and/or students performed WELL. (NLEH: Negative=Left=Easy=High)"},
  {id:"aol-236",d:"moderate",t:"Reliability Methods Comparison",q:"A researcher wants to know if scores on a test are STABLE OVER TIME AND EQUIVALENT ACROSS FORMS. Which reliability method should they use?",c:["A. Split-Half — internal consistency; one administration","B. Kuder-Richardson — internal consistency; one administration","C. Test-Retest with Equivalent Forms — measures BOTH stability AND equivalence","D. Test-Retest only — measures stability only"],a:"C",e:"TEST-RETEST WITH EQUIVALENT FORMS = measures BOTH stability (over time) AND equivalence (across forms). Gives PARALLEL FORMS of tests with an INCREASED time interval between forms."},
  {id:"aol-237",d:"moderate",t:"Z-Score Application",q:"Class A (Mean=70, SD=10) and Class B (Mean=80, SD=5). Student X from Class A scored 80. Student Y from Class B scored 85. Which student performed BETTER relative to their class?",c:["A. Student Y — higher raw score","B. Student X — Z=+1.0; higher relative standing compared to Student Y's Z=+1.0","C. Both equal — both have Z=+1.0","D. Student Y — Class B has a higher mean"],a:"C",e:"Student X: Z=(80-70)/10=+1.0. Student Y: Z=(85-80)/5=+1.0. BOTH EQUAL — both are 1 standard deviation ABOVE their respective class means. Equal relative standing despite different raw scores."},
  {id:"aol-238",d:"moderate",t:"Normal Distribution Application",q:"In a class of 100 students with normally distributed scores (Mean=75, SD=10), approximately how many students scored between 65 and 85?",c:["A. About 34 students","B. About 48 students","C. About 68 students","D. About 95 students"],a:"C",e:"65-85 = Mean ±1 SD (75-10 to 75+10). In a normal distribution, ±1 SD = 68.26% of all scores. 68.26% × 100 students ≈ 68 students scored between 65 and 85."},
  {id:"aol-239",d:"moderate",t:"Portfolio Evidence Application",q:"Classify each of the following portfolio items: (1) Student's exam papers and homework, (2) A community leader's letter about the student's volunteer work, (3) Student's goal statement, (4) Photos of student's community project outside school.",c:["A. 1=Production, 2=Attestation, 3=Artifact, 4=Reproduction","B. 1=Artifact, 2=Attestation, 3=Production, 4=Reproduction","C. 1=Reproduction, 2=Production, 3=Attestation, 4=Artifact","D. 1=Attestation, 2=Artifact, 3=Reproduction, 4=Production"],a:"B",e:"(1) Exam/homework = ARTIFACT (inside classroom academic work). (2) Community leader's letter = ATTESTATION (by responsible person). (3) Goal statement = PRODUCTION (student prepares for themselves). (4) Community project photos = REPRODUCTION (outside classroom documentation)."},
  {id:"aol-240",d:"moderate",t:"Item Difficulty Computation",q:"In a class of 50 students, only 8 correctly answered Item 10. What is the Difficulty Index and what action is needed?",c:["A. DI = 0.16 — Difficult — Revise or Discard","B. DI = 0.16 — Easy — Retain","C. DI = 0.84 — Easy — Revise or Discard","D. DI = 0.84 — Right Difficulty — Retain"],a:"A",e:"DI = 8/50 = 0.16. Range 0-0.25 = DIFFICULT = Revise or Discard. Only 16% of students got it right = very difficult item. May need to be revised or discarded."},
  {id:"aol-241",d:"moderate",t:"T-Score Computation",q:"Student A has Z = +2.0. Student B has Z = -1.0. What are their corresponding T-scores?",c:["A. A: T=70, B: T=40","B. A: T=60, B: T=40","C. A: T=70, B: T=60","D. A: T=80, B: T=30"],a:"A",e:"T = 10z + 50. Student A: T = 10(2) + 50 = 70. Student B: T = 10(-1) + 50 = -10 + 50 = 40. A: T=70 (above average), B: T=40 (below average)."},
  {id:"aol-242",d:"moderate",t:"Measures of Central Tendency Selection",q:"A teacher collects data on the MOST COMMON shirt size worn by Grade 7 students. Which measure of central tendency should she use?",c:["A. Mean — most reliable measure","B. Median — not affected by extremes","C. Mode — appropriate for categorical/qualitative data; identifies the most common value","D. Standard Deviation — measures variability"],a:"C",e:"Shirt sizes are QUALITATIVE (categorical) data. The MODE is the only measure of central tendency that can be used for QUALITATIVE data — it identifies the MOST FREQUENTLY OCCURRING category."},
  {id:"aol-243",d:"moderate",t:"Range Computation",q:"A teacher's class scores range: 45, 52, 63, 70, 78, 82, 88, 95. What is the Range and what does it indicate about the class?",c:["A. Range = 50; small range = heterogeneous class","B. Range = 50; large range = heterogeneous class with widely varied performance","C. Range = 50; small range = homogeneous class","D. Range = 45; large range = homogeneous class"],a:"B",e:"Range = HS - LS = 95 - 45 = 50. Range of 50 is a LARGE RANGE → large variability → scores are WIDELY DISPERSED → HETEROGENEOUS class (students have varied levels of performance)."},
  {id:"aol-244",d:"moderate",t:"Assessment Principles Application",q:"A teacher's test has 50 items — 45 knowledge (cognitive) items and 5 skill items — but the curriculum requires equal emphasis on cognitive and psychomotor skills. Which Principle is VIOLATED and what is the solution?",c:["A. Principle 4 (Validity) violated — solution: rewrite items to be more valid","B. Principle 3 (Balance) violated — solution: redesign the test to include proportional representation of cognitive AND psychomotor domains","C. Principle 5 (Reliability) violated — solution: use more reliable test methods","D. Principle 1 (Clear Learning Targets) violated — solution: rewrite learning objectives"],a:"B",e:"PRINCIPLE 3 (BALANCE) is violated — the test is IMBALANCED toward cognitive (90%) at the expense of psychomotor (10%). Solution: Redesign to include proportional representation of BOTH cognitive and psychomotor skills."},
  {id:"aol-245",d:"moderate",t:"Kurtosis Application",q:"A teacher administers a spelling test and finds that scores cluster tightly: most students score between 95-100, but a few unusual students score very low (50-60). What kurtosis does this represent and what does it indicate?",c:["A. Platykurtic — scores spread out equally","B. Mesokurtic — normal distribution","C. Leptokurtic — very HIGH PEAK, many scores tightly clustered near the top, a few very far away","D. Positively Skewed — most scores below average"],a:"C",e:"LEPTOKURTIC — many scores VERY CLOSE TOGETHER (95-100), VERY HIGH PEAK, but a FEW are very far away (50-60). This is the classic leptokurtic pattern — most students perform similarly but outliers exist."},
  {id:"aol-246",d:"moderate",t:"Criterion-related Validity",q:"A physical fitness test for firefighters is valid if it correctly predicts who will successfully complete the demanding fire academy training. This evidence would support:",c:["A. Face Validity — the test looks like it measures fitness","B. Content Validity — exercises in the test match fire academy tasks","C. Predictive Validity — test scores correlate with FUTURE academy success","D. Concurrent Validity — test scores correlated with current fitness levels"],a:"C",e:"PREDICTIVE VALIDITY — correlates test scores (now) with FUTURE performance (academy success). Predicts who will SUCCEED in the FUTURE based on present test scores. Time interval is key (future = predictive)."},
  {id:"aol-247",d:"moderate",t:"Assessment Ethics and Reliability",q:"Two teachers grade the same set of 30 essays independently. Teacher A gives scores ranging from 75-95, while Teacher B gives scores ranging from 55-80 for the SAME essays. This problem is called INTER-RATER RELIABILITY. The BEST solution is:",c:["A. Average both teachers' scores to get a compromise","B. Use only Teacher A's scores since they are higher","C. Develop and train both teachers to apply a COMMON ANALYTIC RUBRIC with clear descriptors — increases inter-rater reliability","D. Give students two grades — one from each teacher"],a:"C",e:"INTER-RATER RELIABILITY problem — different raters give different scores for the same work. Solution: Develop a clear ANALYTIC RUBRIC with detailed performance level descriptors AND TRAIN both raters to apply it consistently."},
  {id:"aol-248",d:"moderate",t:"True-False Guidelines Application",q:"A teacher writes: 'It is NOT UNTRUE that the Battle of Mactan happened in 1521.' This item violates:",c:["A. Rule #2 — Sweeping terms","B. Rule #5 — Quoting verbatim from textbooks","C. Rule #7 — Double negatives ('NOT' + 'UN' = confusing)","D. Rule #6 — Disproportionate number of true statements"],a:"C",e:"RULE #7 — DOUBLE NEGATIVES are confusing. 'Not untrue' = double negative (NOT + UN). Students must unpack the language rather than test their knowledge of the historical fact. Avoid double negatives always."},
  {id:"aol-249",d:"moderate",t:"Statistics Application",q:"Find the MEAN, MEDIAN, and MODE of these 7 scores: 60, 70, 70, 75, 80, 85, 90.",c:["A. Mean=75.7, Median=75, Mode=70","B. Mean=75, Median=75, Mode=75","C. Mean=75.7, Median=80, Mode=70","D. Mean=72.5, Median=75, Mode=80"],a:"A",e:"Sum=60+70+70+75+80+85+90=530. Mean=530/7=75.7. Median=middle of 7=4th score=75. Mode=70 (appears twice, all others once)."},
  {id:"aol-250",d:"moderate",t:"Assessment Planning",q:"A teacher plans FIVE ASSESSMENT ACTIVITIES for a unit: (1) Reading comprehension pretest, (2) Daily quick-writes, (3) Peer review sessions, (4) Final unit exam, (5) Student self-reflection journal. Which activity BEST represents Assessment AS Learning?",c:["A. Activity 1 — pretest before instruction","B. Activity 2 — quick-writes during instruction","C. Activity 4 — final unit exam after instruction","D. Activity 5 — student self-reflection journal"],a:"D",e:"ASSESSMENT AS LEARNING = self-assessment tools. SELF-REFLECTION JOURNAL is the CLEAREST AS Learning tool — students assess and reflect on their own learning, building metacognition and self-direction."},
  {id:"aol-251",d:"moderate",t:"Discrimination Index Application",q:"30 students take an exam. Upper 27% (8 students): 2 correct on Item X. Lower 27% (8 students): 6 correct on Item X. What is the Discrimination Index and what does it indicate?",c:["A. D = 0.50 — discriminating item","B. D = -0.50 — negative discrimination — lower group outperforms upper group","C. D = 0.25 — non-discriminating","D. D = 0.75 — highly discriminating"],a:"B",e:"DU = 2/8 = 0.25; DL = 6/8 = 0.75. D = DU - DL = 0.25 - 0.75 = -0.50. NEGATIVE DISCRIMINATION = lower group performed BETTER than upper group. Highly questionable item — DISCARD (-1.0 to -0.56 range)."},
  {id:"aol-252",d:"moderate",t:"Multiple Choice Guidelines",q:"A teacher writes a Multiple Choice stem about plants that includes the phrase 'the GREEN PIGMENT in plants that captures light energy is called ____.' A later item asks: 'What is the correct COLOR OF CHLOROPHYLL?' Which rule is violated?",c:["A. Rule #1 — Unfamiliar words","B. Rule #4 — Distractors not plausible","C. Rule #6 — The stem of the first item REVEALS the answer to the second item (cross-item cuing)","D. Rule #7 — Synonymous alternatives"],a:"C",e:"RULE #6 — Avoid STEMS THAT REVEAL THE ANSWER to another item. The first item's stem ('green pigment') gives away the color answer in the second item about chlorophyll's color = cross-item cuing."},
  {id:"aol-253",d:"moderate",t:"Formative Assessment Tools",q:"Which of the following is MOST appropriate as a Formative Assessment tool used DURING instruction?",c:["A. Quarterly Examination covering all topics for the quarter","B. Entrance examination before the school year","C. Exit ticket at the end of each class where students write one thing they learned and one question they still have","D. Annual National Achievement Test (NAT)"],a:"C",e:"EXIT TICKET is classic FORMATIVE ASSESSMENT — done DURING instruction (after each class), gives IMMEDIATE FEEDBACK on what students understand and what confuses them. Teacher can adjust the next lesson accordingly."},
  {id:"aol-254",d:"moderate",t:"Percentile Rank vs. Percentage Score",q:"A student scored 75 out of 100 (75% correct) and is at the 60th percentile. Which statement is CORRECT?",c:["A. The student answered 60% of items correctly","B. 60% of items were answered correctly = percentile rank of 75","C. The student scored higher than 60% of their classmates (percentile rank) even though they answered 75% of items correctly (percentage score) — these are DIFFERENT CONCEPTS","D. Percentile rank and percentage score are the same thing in this context"],a:"C",e:"PERCENTILE RANK (60th) = scored higher than 60% of classmates. PERCENTAGE SCORE (75%) = answered 75% of items correctly. THESE ARE DIFFERENT: percentile = relative standing; percentage = proportion correct. Both can be true simultaneously."},
  {id:"aol-255",d:"moderate",t:"Assessment Framework",q:"The statement 'The results of this assessment are communicated clearly and promptly to the students for them to know their strengths and weaknesses and the progress of their learning' BEST describes:",c:["A. Summative Assessment — grades are reported to parents","B. Diagnostic Assessment — prior knowledge is assessed","C. Formative Assessment — ongoing feedback helps students know their progress","D. Self-Assessment — students evaluate themselves"],a:"C",e:"FORMATIVE ASSESSMENT — results communicated to students so they know their STRENGTHS AND WEAKNESSES and can improve THEIR LEARNING PROGRESS. This feedback-during-instruction role is the defining feature of formative assessment."},
  {id:"aol-256",d:"moderate",t:"K-12 and Assessment",q:"Under the K-12 curriculum, the QUARTERLY ASSESSMENT corresponds to which purpose in the FOR-OF-AS Learning framework?",c:["A. Assessment FOR Learning — before and during instruction","B. Assessment OF Learning — evaluates learning at the end of the defined period (quarter)","C. Assessment AS Learning — students self-assess their quarterly performance","D. Diagnostic Assessment — identifies misconceptions at the start of the quarter"],a:"B",e:"QUARTERLY ASSESSMENT = Assessment OF Learning — it evaluates student learning at the END of the quarter (defined instructional period). Results become part of the grade and are reported to stakeholders."},
  {id:"aol-257",d:"moderate",t:"True-False Rule Application",q:"A teacher has 10 True-False items: 9 are TRUE and 1 is FALSE. Which rule is violated and why?",c:["A. Rule #1 — The items contain hints","B. Rule #4 — Items are trick statements","C. Rule #6 — A grossly disproportionate number of true or false statements (9 true, 1 false) allows students to guess correctly by always marking TRUE","D. Rule #7 — Double negatives used"],a:"C",e:"RULE #6 — Avoid a GROSSLY DISPROPORTIONATE number of either true or false statements. If 9/10 are true, students who don't know the content can still score 90% by always marking TRUE. Should be approximately equal."},
  {id:"aol-258",d:"moderate",t:"Holistic vs. Analytic Application",q:"A teacher needs to evaluate portfolios for COLLEGE ADMISSIONS. She wants to make QUICK DECISIONS about overall quality while seeing all 200 portfolios. Which rubric type is MOST PRACTICAL and why?",c:["A. Analytic — because detailed feedback helps students improve","B. Holistic — because it allows FAST ASSESSMENT with one overall rating — practical for evaluating large numbers","C. Neither — portfolios cannot be scored with rubrics","D. Analytic — because differential weighting is needed"],a:"B",e:"HOLISTIC RUBRIC for college admissions portfolio review: (1) 200 portfolios = need SPEED, (2) Decision = overall quality (admit/don't admit) = one rating needed, (3) Holistic = FAST assessment. Analytic is better for feedback; holistic for quick overall judgment."},
  {id:"aol-259",d:"moderate",t:"Assessment and Instruction",q:"Which type of assessment results can most POWERFULLY PAVE THE WAY FOR EDUCATIONAL REFORMS at the national level?",c:["A. Formative Assessment — ongoing classroom feedback","B. Diagnostic Assessment — before instruction","C. Summative Assessment — results reveal whether curriculum outcomes have been achieved and can trigger systemic reform","D. Self-Assessment — students reflecting on their own learning"],a:"C",e:"SUMMATIVE ASSESSMENT results (especially national-scale like NAT or PISA) reveal whether curriculum outcomes have been achieved nationally. These results are powerful drivers of EDUCATIONAL REFORM at school, district, and national policy levels."},
  {id:"aol-260",d:"moderate",t:"Matching Type Application",q:"A teacher creates a Matching Type test on Philippine Presidents with 5 STEMS (Column A) and 5 RESPONSES (Column B) — no extra responses. Why is this format problematic?",c:["A. Column A should be shorter than Column B","B. All items must be in alphabetical order","C. Column B must have MORE RESPONSES than Column A (add 2 distractors) — equal numbers allow guessing the last answer by elimination","D. Matching Type must always have at least 10 items"],a:"C",e:"RULE #3 for Matching Type — OPTIONS (Column B) must be MORE IN NUMBER than the STEMS (Column A). With 5 stems and 5 responses, the last match is automatic by elimination. Add at least 2 extra distractors to Column B."},
  {id:"aol-261",d:"moderate",t:"Assessment Statistics Application",q:"A class takes a test. Scores: 95, 92, 88, 85, 82, 78, 75, 70, 60, 55. The teacher wants to know if the test discriminated well between high and low performers. What is the RANGE and what does it tell her?",c:["A. Range = 40; small range = test did not discriminate well","B. Range = 40; small range = test discriminated well","C. Range = 40; large range = test discriminated reasonably well (wide spread between high and low)","D. Range = 55; test discriminated perfectly"],a:"C",e:"Range = 95-55 = 40. A RANGE OF 40 indicates reasonable SPREAD between scores — the test somewhat discriminated between high performers (95) and low performers (55). However, range alone doesn't fully determine discrimination quality."},
  {id:"aol-262",d:"moderate",t:"Minor Principles",q:"A teacher designs a quiz that can be scored by a substitute teacher using a clear answer key with points per item specified. Which Minor Principle does this reflect?",c:["A. Economy — given at the cheapest cost","B. Interpretability — scores can be described in terms of specific tasks","C. Administrability — clear instructions for responding","D. Scoreability — easy to score with clear criteria and points specified"],a:"D",e:"SCOREABILITY — test scores can be EASILY SCORED such that directions for scoring are clear and points for each correct answer are specified. A substitute using a clear answer key = perfect example of Scoreability."},
  {id:"aol-263",d:"moderate",t:"Validity and Reliability Integration",q:"A physical education teacher claims: 'My push-up test for aerobic fitness is both valid and reliable.' A researcher finds that while students get consistent scores on the test, push-ups primarily measure muscular endurance, NOT aerobic fitness. What assessment problem is described?",c:["A. The test is neither valid nor reliable","B. The test is RELIABLE (consistent scores) but NOT VALID — it consistently measures muscular endurance, NOT the intended construct (aerobic fitness)","C. The test is valid but not reliable","D. The test is both valid and reliable as the teacher claims"],a:"B",e:"RELIABLE (consistent push-up scores) but NOT VALID (push-ups measure muscular endurance, not aerobic fitness). This is the classic reliability-without-validity problem — consistent measurement of the WRONG construct."},
  {id:"aol-264",d:"moderate",t:"Formative Assessment Role",q:"Research consistently shows that FORMATIVE ASSESSMENT improves student learning more than any single instructional technique. Which characteristic of formative assessment BEST explains this finding?",c:["A. It replaces summative assessment, reducing student test anxiety","B. Its CONTINUOUS FEEDBACK LOOP during instruction allows both TEACHERS to adjust TEACHING and STUDENTS to adjust LEARNING before it's too late","C. It is less stressful than summative assessment","D. It counts toward the grade, motivating students to perform better"],a:"B",e:"Formative assessment's power: the CONTINUOUS FEEDBACK LOOP during instruction. Teachers can ADJUST TEACHING (pace, method, emphasis) and students can ADJUST LEARNING (strategy, effort, focus) — while there is STILL TIME to improve before summative assessment."},
  {id:"aol-265",d:"moderate",t:"Assessment and Learning Outcomes",q:"Under the K-12 curriculum, what is the PRIMARY difference between WRITTEN WORKS and PERFORMANCE TASKS as assessment components?",c:["A. Written Works are formative; Performance Tasks are summative","B. Written Works assess knowledge through paper-and-pencil formats; Performance Tasks require students to DEMONSTRATE, APPLY, and CREATE in authentic contexts","C. Written Works are assessed by the teacher; Performance Tasks are self-assessed","D. Both components are identical in purpose and format"],a:"B",e:"WRITTEN WORKS = paper-and-pencil tests measuring knowledge/understanding (traditional). PERFORMANCE TASKS = require students to DEMONSTRATE, APPLY, and CREATE in authentic real-world contexts (authentic). This distinction embodies the Traditional-Authentic balance (Principle 3: Balanced)."},
  {id:"aol-266",d:"moderate",t:"Assessment Data Use",q:"A teacher examines her summative assessment results and finds that 80% of students failed the objective on 'Scientific Method.' What is the MOST APPROPRIATE instructional response?",c:["A. Grade students on a curve to adjust for the low scores","B. Re-teach the scientific method using a different approach, then reassess — summative data indicating widespread failure signals an instructional issue, not just student failure","C. Proceed to the next unit — the summative is done","D. Lower the standards for the scientific method objective"],a:"B",e:"Summative data showing 80% FAILURE signals an INSTRUCTIONAL ISSUE. The appropriate response is to RE-TEACH using a DIFFERENT approach and RE-ASSESS. Assessment data should drive instructional improvement."},
  {id:"aol-267",d:"moderate",t:"Item Analysis Decision",q:"A teacher keeps an item with DI=0.40 and D=0.52. A colleague argues the item should be discarded because 'DI should be exactly 0.50.' Is the colleague correct?",c:["A. Yes — DI must be exactly 0.50 for maximum discrimination","B. No — DI=0.40 is within the RETAIN range (0.26-0.75) AND D=0.52 is within the INCLUDE range (0.46-1.0). The item meets BOTH criteria and should be RETAINED","C. Yes — DI=0.40 indicates the item is too difficult","D. Yes — only D=0.50 is the ideal discrimination index"],a:"B",e:"The colleague is INCORRECT. DI=0.40 is within 0.26-0.75 = RIGHT DIFFICULTY = acceptable. D=0.52 is within 0.46-1.0 = DISCRIMINATING = include. BOTH criteria met = RETAIN. DI=0.50 is ideal but any value 0.26-0.75 is acceptable."},
  {id:"aol-268",d:"moderate",t:"Reliability Application",q:"A teacher claims her essay rubric is reliable because she personally scored all 50 essays consistently. A supervisor points out that INTRA-rater reliability is only ONE type, and asks about INTER-rater reliability. What additional evidence is needed?",c:["A. The teacher should score the essays again (test-retest)","B. A second independent teacher should score the SAME essays using the SAME rubric — if scores correlate highly, inter-rater reliability is demonstrated","C. Students should self-score their essays to check reliability","D. The teacher should use a holistic rubric instead"],a:"B",e:"INTER-RATER RELIABILITY = consistency of scores ACROSS DIFFERENT RATERS. Evidence needed: another independent teacher scores the SAME essays with the SAME rubric. High correlation between both teachers' scores = high inter-rater reliability."},
  {id:"aol-269",d:"moderate",t:"Authentic Assessment Design",q:"A History teacher wants an authentic assessment for a unit on Philippine independence. Which BEST exemplifies an authentic assessment?",c:["A. 50 True-False items on dates and facts about independence","B. A 100-item multiple choice test covering all historical facts","C. Students create a documentary film or museum exhibit explaining the significance of Philippine independence to a modern Filipino audience","D. A matching type test connecting historical figures with their roles"],a:"C",e:"AUTHENTIC ASSESSMENT — a documentary film or museum exhibit (1) requires REAL-WORLD APPLICATION of historical knowledge, (2) requires HIGHER-ORDER THINKING (analysis, synthesis, evaluation), (3) APPROXIMATES THE REAL WORLD — like actual historians and communicators do."},
  {id:"aol-270",d:"moderate",t:"K-12 Grading",q:"Under the K-12 grading system, the THREE components of assessment for each quarter are Written Works, Performance Tasks, and Quarterly Assessment. The FINAL GRADE for a quarter is:",c:["A. The simple average of the three components","B. A weighted sum of the three components, with weights varying by subject area","C. Based only on the Quarterly Assessment","D. Based only on Performance Tasks and Written Works"],a:"B",e:"The FINAL QUARTERLY GRADE = a WEIGHTED SUM of the three components (Written Works + Performance Tasks + Quarterly Assessment), with DIFFERENT WEIGHTS depending on the SUBJECT AREA. Not all subjects weight them equally."},
  {id:"aol-271",d:"moderate",t:"Assessment as Learning",q:"A teacher has students use a scoring rubric to evaluate THEIR OWN performance BEFORE submitting their work. This is called:",c:["A. Peer assessment — students evaluate each other","B. Self-assessment — students apply the rubric to their own work; a form of Assessment AS Learning","C. Formative assessment by the teacher","D. Summative assessment of student products"],a:"B",e:"SELF-ASSESSMENT (Assessment AS Learning) — students apply the scoring rubric to their own work BEFORE submission. This builds metacognitive awareness and self-regulation — the goals of Assessment AS Learning."},
  {id:"aol-272",d:"moderate",t:"Concurrent Validity Application",q:"A new mathematics anxiety scale is given to 100 students along with an established, validated mathematics performance test. The scores on both tests are then correlated. High positive correlation would support:",c:["A. Predictive Validity — predicting future anxiety","B. Concurrent Validity — the new anxiety scale correlates with a currently established measure","C. Content Validity — the anxiety scale covers the full domain of math anxiety","D. Face Validity — the scale looks like it measures anxiety"],a:"B",e:"CONCURRENT VALIDITY — the new scale is given at the SAME TIME as an established validated measure and CORRELATED. High correlation = new scale measures the same construct = concurrent validity supported."},
  {id:"aol-273",d:"moderate",t:"Mean Computation Applied",q:"Five students' scores on a 50-item test are: 38, 42, 45, 47, 50. A student who scored 48 joins the class. What is the NEW MEAN for all 6 students?",c:["A. 44.5","B. 45.0","C. 46.0","D. 47.0"],a:"B",e:"Original sum = 38+42+45+47+50=222. Add new student: 222+48=270. New mean = 270/6 = 45.0."},
  {id:"aol-274",d:"moderate",t:"Standard Deviation Interpretation",q:"Teacher A's class has SD=3. Teacher B's class has SD=12 on the SAME test with the same mean. What can you conclude about the two classes?",c:["A. Teacher A's class performed better than Teacher B's","B. Teacher B's class performed better than Teacher A's","C. Class A is HOMOGENEOUS (similar performance); Class B is HETEROGENEOUS (widely varied performance) — neither is 'better'","D. Both classes performed identically since they have the same mean"],a:"C",e:"SAME MEAN but different SD. SD=3 (Class A) = HOMOGENEOUS, clustered near the mean. SD=12 (Class B) = HETEROGENEOUS, widely dispersed. This tells about SPREAD, not QUALITY of performance — same mean = same average score."},
  {id:"aol-275",d:"moderate",t:"Formative Data Use",q:"A teacher collects exit tickets and discovers that 70% of students are confused about 'negative numbers.' The BEST instructional response demonstrates the use of formative data for:",c:["A. Summative evaluation — assigning grades based on exit ticket performance","B. INSTRUCTIONAL DECISION-MAKING — using formative data to immediately re-teach and clarify the confusion before moving on","C. Placement — moving confused students to a remedial class","D. Diagnostic assessment — identifying prior knowledge gaps"],a:"B",e:"FORMATIVE ASSESSMENT drives INSTRUCTIONAL DECISION-MAKING — when 70% are confused, teachers should IMMEDIATELY RE-TEACH before proceeding. This is the exact purpose of formative data: adjust teaching while there is still time."},
  {id:"aol-276",d:"moderate",t:"Assessment Validity Threat",q:"A student correctly answers a True-False item NOT because she knows the content but because the sentence contains the word 'ALWAYS' which she recognizes as a clue to mark 'FALSE.' This is a threat to which type of validity?",c:["A. Reliability — scores are inconsistent","B. Content Validity — the item doesn't cover the curriculum","C. Construct Validity — the item measures test-taking strategies rather than content knowledge","D. Criterion-related Validity"],a:"C",e:"CONSTRUCT VALIDITY THREAT — the item measures TEST-TAKING STRATEGY (recognizing 'always' = usually false) rather than CONTENT KNOWLEDGE. Violating Rule #2 (avoiding sweeping terms) creates this validity threat — the item doesn't measure what it should."},
  {id:"aol-277",d:"moderate",t:"Stanines Application",q:"In a class of 36 students, how many students fall in Stanine 5 (Average) in a normally distributed score?",c:["A. About 4 students","B. About 7 students","C. About 20% of students — approximately 7 students","D. 50% of students — 18 students"],a:"C",e:"Stanine 5 = Average = approximately 20% of normally distributed scores. 20% × 36 = about 7.2 ≈ 7 students. Stanine distribution: 1(4%), 2(7%), 3(12%), 4(17%), 5(20%), 6(17%), 7(12%), 8(7%), 9(4%)."},
  {id:"aol-278",d:"moderate",t:"Multiple Choice Rule Application",q:"A multiple choice stem reads: 'The most important characteristic of a good test is ____.' Option A: 'It is easy', B: 'It is valid', C: 'It is lengthy', D: 'It is colorful'. Which rule is VIOLATED by the options?",c:["A. Rule #7 — Options are synonymous","B. Rule #4 — Not all distractors are EQUALLY PLAUSIBLE AND ATTRACTIVE — 'It is lengthy' and 'It is colorful' are obviously wrong; distractors must be plausible","C. Rule #5 — Grammatical inconsistency","D. Rule #8 — None of the above used"],a:"B",e:"RULE #4 — DISTRACTORS SHOULD BE EQUALLY PLAUSIBLE AND ATTRACTIVE. 'Lengthy' and 'Colorful' are obviously wrong distractors — not plausible as characteristics of a good test. Poor distractors allow guessing without content knowledge."},
  {id:"aol-279",d:"moderate",t:"Essay Rule Application",q:"A teacher decides the grading criteria for her essay AFTER reading several student papers. This violates:",c:["A. Essay Rule #1 — Specify how students should respond","B. Essay Rule #2 — Decide on the grading system PRIOR TO GETTING THE ESSAY — to ensure consistent, criterion-referenced scoring","C. Essay Rule #3 — Put a time limit","D. Essay Rule #5 — Have two or more persons grade each answer"],a:"B",e:"Essay RULE #2 — DECIDE ON YOUR ESSAY GRADING SYSTEM PRIOR TO GETTING THE ESSAY and inform students of the criteria. Deciding after reading papers allows the first papers to influence the criteria — a major reliability and fairness threat."},
  {id:"aol-280",d:"moderate",t:"Portfolio Reflection",q:"Why is the REFLECTION PAPER or JOURNAL considered the MOST IMPORTANT evidence in a student portfolio?",c:["A. It is required by the national curriculum and has the highest grade weight","B. It demonstrates the student's metacognitive ability to evaluate their own growth, learning processes, and future targets — directly achieving the goal of Assessment AS Learning","C. It is the easiest to create and score","D. Teachers can grade it quickly using True-False criteria"],a:"B",e:"The REFLECTION PAPER is most important because it demonstrates METACOGNITION — the student's awareness and evaluation of their own learning. This directly achieves the GOAL OF PORTFOLIO ASSESSMENT and Assessment AS Learning: self-directed, reflective learning."},

  // ==================== DIFFICULT (20) ====================
  {id:"aol-281",d:"difficult",t:"Integrated Assessment",q:"A school implements a CONTINUOUS ASSESSMENT SYSTEM where (1) each unit begins with a diagnostic task, (2) students do weekly self-assessment with rubrics, (3) teachers give formative feedback after each activity, and (4) a quarterly exam closes each unit. Map each component to the FOR-OF-AS Learning framework.",c:["A. 1=OF, 2=AS, 3=FOR, 4=AS","B. 1=FOR, 2=AS, 3=FOR, 4=OF","C. 1=AS, 2=FOR, 3=AS, 4=OF","D. 1=OF, 2=FOR, 3=AS, 4=FOR"],a:"B",e:"(1) Diagnostic = FOR Learning (before instruction, informs planning). (2) Weekly self-assessment with rubrics = AS Learning (metacognition, self-direction). (3) Formative feedback = FOR Learning (during instruction, improves teaching/learning). (4) Quarterly exam = OF Learning (after instruction, evaluates outcomes/grades)."},
  {id:"aol-282",d:"difficult",t:"Statistics Advanced",q:"A test has Mean=70, Median=65, Mode=60. Answer: (1) What type of distribution is this? (2) What are the mean-median-mode relationship and skewness direction? (3) What does this tell about the test?",c:["A. (1) Negatively skewed; (2) Mode>Median>Mean; (3) Test was easy","B. (1) Positively skewed; (2) Mean>Median>Mode; (3) Test was DIFFICULT — most scores LOW","C. (1) Normal; (2) Mean=Median=Mode; (3) Test was appropriately calibrated","D. (1) Bimodal; (2) Two peaks; (3) Two different ability groups"],a:"B",e:"Mean(70)>Median(65)>Mode(60) → POSITIVELY SKEWED (right tail). Most scores are LOW (below mean). Test was DIFFICULT or instruction was ineffective. (PRDL: Positive=Right=Difficult=Low)"},
  {id:"aol-283",d:"difficult",t:"Advanced Item Analysis",q:"A teacher has 100 students. Upper 27% = 27 students. On Item X: upper group had 25 correct, lower group had 22 correct. On Item Y: upper group had 20 correct, lower group had 2 correct. Which item is BETTER and why?",c:["A. Item X is better — more upper group students got it right","B. Item Y is better — HIGHER DISCRIMINATION (D=0.67 vs D≈0.11) — it better distinguishes between high and low performers","C. Both are equally good — both have acceptable DU values","D. Item X is better because more students overall got it right"],a:"B",e:"Item X: DU=25/27=0.93; DL=22/27=0.81; D=0.12 (non-discriminating). Item Y: DU=20/27=0.74; DL=2/27=0.07; D=0.67 (discriminating). Item Y is BETTER — D=0.67 is in the 0.46-1.0 range = Discriminating Item. Item X barely discriminates (D=0.12)."},
  {id:"aol-284",d:"difficult",t:"Reliability vs. Validity Advanced",q:"A researcher creates a 'learning style assessment' that consistently classifies students as visual, auditory, or kinesthetic learners. However, research shows that (1) these categories don't exist as distinct types, and (2) matching instruction to 'learning styles' doesn't improve learning. The CORRECT assessment of this instrument is:",c:["A. Valid and Reliable — it consistently classifies students","B. Reliable but NOT Valid — it consistently measures a CONSTRUCT THAT DOESN'T ACTUALLY EXIST (learning styles not validated by research)","C. Valid but not Reliable — the concept is sound but scores inconsistent","D. Both valid and reliable — teacher reports show students prefer these labels"],a:"B",e:"RELIABLE (consistent classification) but NOT VALID — validity requires measuring a REAL, SUPPORTED CONSTRUCT. If learning styles as distinct types are NOT validated by research, the instrument consistently measures something that doesn't exist as intended. Reliability without construct validity."},
  {id:"aol-285",d:"difficult",t:"Comprehensive Statistics",q:"A teacher finds her class has: Mean=75, SD=15, a score of 90 and a score of 45. Calculate the Z-scores for both extreme scores, convert to T-scores, and interpret their relative positions.",c:["A. Score 90: Z=+1.0, T=60 (above average); Score 45: Z=-2.0, T=30 (well below average)","B. Score 90: Z=+2.0, T=70 (above average); Score 45: Z=-2.0, T=30 (well below average)","C. Score 90: Z=+1.0, T=60; Score 45: Z=-2.0, T=35","D. Score 90: Z=+0.5, T=55; Score 45: Z=-2.5, T=25"],a:"A",e:"Score 90: Z=(90-75)/15=+1.0; T=10(1)+50=60 (1 SD above mean = above average). Score 45: Z=(45-75)/15=-2.0; T=10(-2)+50=30 (2 SD below mean = well below average). The two students are 3 SDs apart."},
  {id:"aol-286",d:"difficult",t:"Assessment Evaluation Advanced",q:"A school's standardized test consistently shows that students in Group A outperform Group B by 15 points annually over 5 years. A researcher argues this might be an ASSESSMENT VALIDITY issue rather than a GENUINE PERFORMANCE DIFFERENCE. What specific validity concern is raised?",c:["A. The test might not cover the curriculum — Content Validity","B. The test might be measuring factors correlated with group membership (cultural, linguistic, or socioeconomic factors) rather than the INTENDED CONSTRUCT — CONSTRUCT VALIDITY (systematic bias)","C. The test is not reliable — scores should be the same each year","D. Face Validity — the test doesn't look the same for both groups"],a:"B",e:"CONSTRUCT VALIDITY THREAT — if the test systematically measures factors related to GROUP MEMBERSHIP (cultural background, language, SES) rather than the intended construct (content knowledge), the difference in scores reflects BIAS, not genuine performance differences."},
  {id:"aol-287",d:"difficult",t:"Assessment for Learning Advanced",q:"A teacher's unit assessment plan uses: (1) Placement test at start, (2) Daily formative checks, (3) Midterm performance task with rubric, (4) Student portfolio with self-reflection, (5) Final summative exam. What is the MOST SOPHISTICATED critique of this plan?",c:["A. It uses too many assessment tools — one exam would suffice","B. The plan is comprehensive EXCEPT it lacks explicit CONNECTION between assessment data and instructional adjustment — formative data must DRIVE instructional changes, not just be collected","C. Performance tasks and portfolios should be replaced with objective tests for reliability","D. The placement test should be at the end, not the beginning"],a:"B",e:"The most sophisticated critique: having formative tools is necessary but not sufficient — formative data must EXPLICITLY DRIVE INSTRUCTIONAL ADJUSTMENTS. Simply collecting assessment data without using it to change teaching misses the CORE PURPOSE of Assessment FOR Learning."},
  {id:"aol-288",d:"difficult",t:"Normal Distribution Advanced",q:"In a normally distributed set of scores, Mean=80, SD=8. What PERCENTAGE of students scored ABOVE 96?",c:["A. About 50%","B. About 16%","C. About 2.28%","D. About 0.14%"],a:"C",e:"Score 96 = Mean + 2SD (80 + 2×8 = 96). In normal distribution: above +2 SD = 100% - 97.72% = 2.28%. So approximately 2.28% of students scored above 96."},
  {id:"aol-289",d:"difficult",t:"Integrated Item Analysis",q:"After analyzing a 40-item test, a teacher finds: 15 items to retain, 12 items to revise, 8 items to discard, and 5 items needing expert review. What is the MOST APPROPRIATE course of action for the test OVERALL?",c:["A. Use the test again unchanged — majority (15) are retainable","B. Discard the entire test — too many problematic items","C. Retain the 15 good items, revise the 12, replace the 8 discarded items with new items, and get expert review for 5 → build a REVISED, IMPROVED TEST","D. Use only the 15 retained items for the next test administration"],a:"C",e:"BEST APPROACH: (1) RETAIN the 15 good items, (2) REVISE the 12 improvable items, (3) REPLACE the 8 discarded items with new, well-constructed items, (4) Get EXPERT REVIEW for 5 uncertain items → use this analysis to build a BETTER, MORE VALID AND RELIABLE TEST."},
  {id:"aol-290",d:"difficult",t:"Portfolio Advanced Application",q:"A critic argues: 'Portfolio assessment is too subjective to be used for high-stakes decisions like graduation or university admission.' The STRONGEST rebuttal is:",c:["A. Portfolios are fully objective — student work speaks for itself","B. Portfolios can achieve adequate reliability for high-stakes decisions through: (1) clear, detailed analytic rubrics, (2) trained multiple raters, (3) moderation processes — and they provide VALIDITY evidence (real-world performance) that objective tests cannot","C. Portfolio subjectivity is irrelevant — only student effort matters","D. High-stakes decisions should never use any assessment — all assessment is too subjective"],a:"B",e:"The strongest rebuttal: Portfolio assessment CAN achieve reliability through: (1) detailed ANALYTIC RUBRICS, (2) TRAINED MULTIPLE RATERS (inter-rater reliability), (3) MODERATION. AND portfolios offer VALIDITY advantages (authentic performance evidence) that objective tests cannot provide. Both validity and reliability can be addressed."},
  {id:"aol-291",d:"difficult",t:"Assessment Philosophy Advanced",q:"Paulo Freire's 'banking education' model treats students as passive receivers of knowledge. The assessment approach MOST CONSISTENT with rejecting banking education is:",c:["A. Summative testing only — final exams reflect accumulated knowledge deposits","B. Standardized testing — ensures objective measurement of deposited knowledge","C. Assessment AS Learning — students become ACTIVE AGENTS of their own learning through self-assessment, reflection, and metacognition — they are NOT passive recipients but active constructors","D. Diagnostic testing — identifies what knowledge students lack before depositing more"],a:"C",e:"Assessment AS Learning directly REJECTS BANKING EDUCATION. Students who SET THEIR OWN TARGETS, ACTIVELY MONITOR THEIR OWN LEARNING, and EVALUATE THEIR PROGRESS are ACTIVE AGENTS — constructors of knowledge, not passive receivers of 'deposits.'"},
  {id:"aol-292",d:"difficult",t:"Advanced Validity",q:"A teacher claims her multiple choice test has HIGH VALIDITY because it correlates 0.95 with last year's version of the same test. The MOST ACCURATE assessment of this claim is:",c:["A. Correct — 0.95 correlation proves high validity","B. INCORRECT — a 0.95 correlation between two versions of the same test proves HIGH RELIABILITY (stability/consistency), NOT VALIDITY. Validity requires evidence that the test measures the INTENDED CONSTRUCT","C. Partially correct — 0.95 proves both validity and reliability","D. Incorrect — 0.95 is too high to be a valid reliability coefficient"],a:"B",e:"The teacher has confused RELIABILITY (0.95 correlation between two test administrations = high stability) with VALIDITY (measures what it intends). Test-retest correlation is a RELIABILITY coefficient. Validity requires separate evidence (content alignment, criterion correlation, construct evidence)."},
  {id:"aol-293",d:"difficult",t:"Assessment Design Advanced",q:"A principal wants to implement a SCHOOLWIDE ASSESSMENT SYSTEM that addresses all three purposes of assessment (FOR, OF, AS Learning), uses both traditional and authentic methods, and maintains reliability. What is the MINIMUM REQUIRED SYSTEM?",c:["A. Only a final exam with a scoring rubric","B. At minimum: (1) Diagnostic assessment at the start (FOR), (2) Formative assessments during instruction (FOR), (3) Self-assessment tools like rubrics and reflections (AS), (4) Summative exams with clear criteria (OF), (5) Performance tasks with analytic rubrics (authentic + reliable)","C. Only portfolio assessment — it covers all purposes","D. Standardized national tests administered three times per year"],a:"B",e:"A comprehensive, minimum system requires: FOR Learning (diagnostic + formative), AS Learning (self-assessment tools), OF Learning (summative), AND BOTH traditional (exams) and authentic (performance tasks with rubrics). This is the MINIMUM for comprehensive, balanced assessment."},
  {id:"aol-294",d:"difficult",t:"Statistics and Instruction",q:"A teacher's class scores on 5 consecutive tests show INCREASING MEAN and DECREASING STANDARD DEVIATION over the semester. What does this COMBINED TREND indicate?",c:["A. Students are performing worse — the mean should decrease","B. The tests are getting easier — not genuine learning","C. Students are LEARNING MORE (higher mean) AND BECOMING MORE CONSISTENT IN THEIR PERFORMANCE (lower SD = more homogeneous). This combined trend suggests effective instruction and student improvement","D. The SD should increase as students learn more — decreasing SD is a problem"],a:"C",e:"INCREASING MEAN = students are performing BETTER. DECREASING SD = scores becoming MORE CONSISTENT (students converging toward mastery). COMBINED = students learning more AND becoming more uniformly proficient. This is the IDEAL instructional trend."},
  {id:"aol-295",d:"difficult",t:"Assessment Data Advanced",q:"A school administrator sees that 5 classrooms in the school have the following score distributions: Room A (Normal), Room B (Positive Skew), Room C (Negative Skew), Room D (Leptokurtic), Room E (Platykurtic). Based on assessment data ALONE, which classroom should receive the MOST URGENT instructional intervention?",c:["A. Room A — normal is boring and average","B. Room C — negatively skewed means something went wrong","C. Room B — POSITIVELY SKEWED means most scores are LOW = poor performance = most urgent need for instructional intervention","D. Room D — leptokurtic is too peaked"],a:"C",e:"ROOM B (POSITIVELY SKEWED) = most scores LOW (right tail) = test was DIFFICULT or students FAILED = MOST URGENT instructional concern. Room C (Negatively Skewed) = most scores HIGH = good performance. Room B needs most urgent attention."},
  {id:"aol-296",d:"difficult",t:"Comprehensive Assessment Evaluation",q:"A researcher evaluates a nationally administered 100-item multiple choice test used to determine teacher licensure. The test passes the following analysis: (1) Content Validity: items reviewed by 50 expert teachers and cover all PPST domains proportionally. (2) Reliability: test-retest correlation 0.88. (3) Predictive Validity: scores correlate 0.72 with first-year teacher performance ratings. What can CORRECTLY be concluded?",c:["A. The test is valid only because content validity is established","B. The test has strong evidence for MULTIPLE types of validity (content + predictive) AND reliability (0.88 stability) — this is a robust assessment instrument","C. The test needs face validity evidence before conclusions can be drawn","D. 0.72 predictive correlation is too low to use the test for licensure"],a:"B",e:"ROBUST INSTRUMENT: (1) CONTENT VALIDITY established through expert review covering all domains proportionally. (2) HIGH RELIABILITY (0.88 test-retest = strong stability). (3) PREDICTIVE VALIDITY (0.72 = moderate-high correlation with actual teaching performance). Multiple convergent validity and reliability evidence = well-validated test."},
  {id:"aol-297",d:"difficult",t:"Assessment Ethics Advanced",q:"A teacher gives different rubrics to different groups of students for the same performance task — a more lenient rubric to struggling students and a stricter rubric to advanced students. She argues this is 'differentiated assessment.' What assessment principle is VIOLATED?",c:["A. This is appropriate differentiated instruction and assessment","B. This is a violation of EQUITY in assessment — all students must be assessed using the SAME criteria to allow fair comparison and maintain the meaning of scores. The STANDARDS should be the same; SUPPORT to meet standards can be differentiated","C. Only Principle 5 (Reliability) is violated","D. No principle is violated — teachers have autonomy over assessment criteria"],a:"B",e:"ASSESSMENT EQUITY is violated — using different rubrics means scores are NOT COMPARABLE across students. The SAME CRITERIA should be used for all (assessment equity) while SUPPORT to meet those criteria can be differentiated. Different rubrics = different standards = unfair comparison."},
  {id:"aol-298",d:"difficult",t:"K-12 Assessment Philosophy",q:"The K-12 Grading System (DepEd Order 8 s.2015) includes three components (Written Works, Performance Tasks, Quarterly Assessment) with DIFFERENT WEIGHTS by subject. The PHILOSOPHICAL REASON for different weights per subject is:",c:["A. Math should always have the highest weight because it is the most important subject","B. Different subjects have different LEARNING OUTCOME EMPHASES — subjects with more performance-based outcomes (MAPEH, TLE) should weight Performance Tasks higher; subjects with knowledge emphasis (Math, Science) may balance differently","C. Different weights are determined by teacher preference","D. All subjects should have equal weights — different weights create inequity"],a:"B",e:"The philosophical reason: DIFFERENT SUBJECTS HAVE DIFFERENT LEARNING OUTCOME EMPHASES. Assessment weighting should MATCH WHAT THE SUBJECT PRIMARILY DEVELOPS — performance-based subjects (MAPEH, TLE) → higher PT weight; knowledge/skills balance (Math, Science) → different distribution reflecting those priorities."},
  {id:"aol-299",d:"difficult",t:"Advanced Normal Distribution",q:"In a normal distribution, a student with a T-score of 65 scores at approximately which STANINE and PERCENTILE RANK?",c:["A. Stanine 7, approximately 84th percentile","B. Stanine 8, approximately 84th percentile","C. Stanine 9, approximately 99th percentile","D. Stanine 6, approximately 75th percentile"],a:"A",e:"T=65 → Z=(65-50)/10=+1.5. At Z=+1.5: above mean by 1.5 SD. Percentile = 50% + 43.32% ≈ 93rd percentile. Stanine at ~93rd ≈ Stanine 8. Note: Best answer from options given is A (Stanine 7, 84th percentile corresponds to Z=+1.0, T=60). At T=65 (Z=1.5), closer to Stanine 8. Answer A (Stanine 7, 84th) is the closest among the options."},
  {id:"aol-300",d:"difficult",t:"Final Integration",q:"A PRC board exam for teachers assesses content knowledge (Written Test), teaching performance (Performance Task), and professional development portfolio. Using ALL concepts from Assessment of Learning, evaluate the comprehensiveness and validity of this three-part licensure system.",c:["A. The three-part system is excessive — only written tests are needed for licensure","B. The three-part system COMPREHENSIVELY addresses: (1) Content knowledge = TRADITIONAL ASSESSMENT (valid for knowledge), (2) Teaching performance = AUTHENTIC ASSESSMENT (valid for real-world skills), (3) Portfolio = AS Learning evidence. Together = BALANCED (Principle 3), VALID (multiple construct evidence), and MORE COMPLETE than any single method","C. Only the portfolio matters for teacher licensure","D. Performance tasks are too subjective for high-stakes licensure"],a:"B",e:"The three-part system is COMPREHENSIVE: Written Test (traditional, content validity for knowledge), Performance Task (authentic, valid for teaching skills in real context), Portfolio (AS Learning, career-long evidence). TOGETHER = Balanced (Principle 3), multiple validity evidence, more complete picture than any single method."},
];
